+        PAGE_KEYS.put(GUIType.COMBAT, COMBAT_KEYS);
+        PAGE_KEYS.put(GUIType.MOVEMENT, MOVEMENT_KEYS);
+        PAGE_KEYS.put(GUIType.RANGED, RANGED_KEYS);
+        PAGE_KEYS.put(GUIType.REALISM, REALISM_KEYS);
+    }
